    try {
      const config = JSON.parse(fs.readFileSync(configPath, "utf-8"));
      mode = config.mode || "stealth";
    } catch { mode = "stealth"; }
  } else if (initialized) {
    mode = "stealth";
  }

  return `Beads Status
Initialized: ${initialized ? "yes" : "no"}
Mode: ${initialized ? mode : "n/a"}
Git hooks: ${hooksInstalled ? "installed" : "not installed"}
Directory: ${initialized ? beadsDir : "n/a"}`;
}
