## Description
Add `coder("logs")` command that returns log directory info.

## Instructions

### Add new case in the switch statement (src/tool/coder-tool.ts):

```typescript
case "logs": {
  const os = await import("node:os");
  const fs = await import("node:fs");
  const path = await import("node:path");

  // Determine log path based on OS
  let logDir: string;
  const platform = os.platform();
  const homeDir = os.homedir();

  if (platform === "darwin") {
    logDir = path.join(homeDir, "Library", "Logs", "opencode");
  } else if (platform === "win32") {
    logDir = path.join(process.env.APPDATA || path.join(homeDir, "AppData", "Roaming"), "opencode", "logs");
  } else {
    logDir = path.join(homeDir, ".config", "opencode", "logs");
  }

  const exists = fs.existsSync(logDir);
  let fileCount = 0;
  let latestFile = "none";

  if (exists) {
    const files = fs.readdirSync(logDir).filter(f => f.endsWith(".log"));
    fileCount = files.length;
    if (files.length > 0) {
      // Sort by mtime descending
      const sorted = files
        .map(f => ({ name: f, mtime: fs.statSync(path.join(logDir, f)).mtime }))
        .sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
      latestFile = sorted[0].name;
    }
  }

  return `OpenCode Logs
Directory: ${logDir}
Exists: ${exists ? "yes" : "no"}
Log files: ${fileCount}
Latest: ${latestFile}`;
}
```

### Update help text to include new command

Add to the help output:
