export async function collectBeadsInfo(): Promise<BeadsInfo> {
  try {
    // Check if bd command exists
    const versionResult = await Bun.$`bd --version`.text();
    const cliVersion = versionResult.trim().split(' ')[2]; // "bd version 0.49.0 ..." -> "0.49.0"

    // Check if .beads/ directory exists
    const projectInitialized = existsSync(join(process.cwd(), '.beads'));

    // Get stats if initialized
    let stats: BeadsStats | null = null;
    if (projectInitialized) {
