          openIssues: statsOutput.summary?.open ?? 0,
          readyToWork: statsOutput.summary?.ready ?? 0
        };
      } catch {
        // Stats command failed, keep null
      }
    }

    return {
      enabled: true,
      cliVersion,
      projectInitialized,
      stats
    };
  } catch {
    // bd command not found or failed
    return {
      enabled: false,
      cliVersion: null,
      projectInitialized: false,
      stats: null
    };
  }
}
