          readyToWork: statsData.summary?.ready ?? 0
        };
      } catch {
        // Stats command failed, keep null
      }
    }

    return {
      enabled: true,
      cliVersion,
      projectInitialized,
      stats
    };
  } catch {
    // bd command not found or failed
    return {
      enabled: false,
      cliVersion: null,
